INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Conversion-focused templates$q$, $q$A library of templates designed for specific goals like lead magnets, webinars, sales pages, and thank-you pages.$q$, 1);
