INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Drag-and-drop course builder$q$, $q$Structure content into courses, lessons, and topics with an intuitive visual builder inside WordPress.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Quiz and assessment engine$q$, $q$Create timed quizzes with multiple question types, custom grading, and detailed results reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Quiz AI Builder$q$, $q$Generate draft quiz questions automatically from a course or lesson description using an integrated AI connection.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Drip-feed content scheduling$q$, $q$Release lessons and topics on a schedule or based on prerequisites to pace learners through a course.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Certificates and badges$q$, $q$Award customizable completion certificates and gamified badges to recognize learner achievement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Course forums and discussions$q$, $q$Enable per-course discussion spaces via bbPress/BuddyPress integration to support learner interaction.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Group management and bulk enrollment$q$, $q$Organize learners into groups, assign group leaders, and bulk-enroll cohorts for corporate or classroom training.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Ecommerce and membership integrations$q$, $q$Sell courses, bundles, and recurring memberships through WooCommerce, Stripe, PayPal, and other payment tools.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$ProPanel reporting dashboard$q$, $q$Track enrollment, completion rates, and learner engagement across all courses from a central dashboard.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Full ownership of course content, branding, and student data since it runs on your own WordPress site$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Mature, deeply featured platform with a large ecosystem of add-ons, themes, and integrations$q$, 1);
