INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Robust quiz, certification, and drip-content tools suited to structured training programs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Flexible licensing that includes unlimited courses and learners on every plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$No free plan or free trial; only a 15-day money-back guarantee$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Requires WordPress hosting and maintenance knowledge, adding overhead versus hosted LMS platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Total cost can rise quickly once premium themes, add-ons, and hosting are factored in$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Steeper learning curve than all-in-one, no-code course platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Recent corporate restructuring, including the 2026 StellarWP brand wind-down under Liquid Web, has created some uncertainty about long-term product direction$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Is LearnDash free to use?$q$, $q$No, LearnDash has no free plan. Plugin licenses start at $199/year for use on one WordPress site, with no free trial, though a 15-day money-back guarantee is offered.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Does LearnDash require a WordPress site?$q$, $q$Yes. LearnDash is a WordPress plugin, so it requires an existing (or new) WordPress installation and compatible hosting to run.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Can I sell courses and memberships with LearnDash?$q$, $q$Yes. LearnDash integrates with WooCommerce, Stripe, PayPal, and other tools to sell individual courses, course bundles, and recurring memberships.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$What happened to LearnDash and StellarWP?$q$, $q$LearnDash was acquired by Liquid Web in 2021 and operated under the StellarWP brand. In 2026, Liquid Web consolidated its WordPress product portfolio and retired the standalone StellarWP brand, with LearnDash continuing as one of Liquid Web's core WordPress products.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$How is LearnDash priced?$q$, $q$LearnDash plugin licenses are billed annually based on the number of sites: $199/year for one site, $399/year for ten sites, and $799/year for unlimited sites. LearnDash Cloud, a hosted option, is also available with its own separate pricing tiers.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Selling online courses$q$, $q$Independent creators and coaches use LearnDash to build, package, and sell courses directly from their own branded WordPress site.$q$, $q$Course creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Corporate training and certification$q$, $q$Companies use LearnDash's group management and reporting tools to deliver structured training programs and track employee certification progress.$q$, $q$Corporate L&D teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Membership and subscription content$q$, $q$Site owners gate premium courses and materials behind recurring memberships, combining LearnDash with WooCommerce or Stripe for billing.$q$, $q$Membership site owners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Academic and institutional programs$q$, $q$Schools and training organizations run blended or fully online programs, using quizzes, drip content, and certificates to structure coursework.$q$, $q$Educational institutions$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$1 Site License$q$, $q$$199$q$, $q$per year$q$, $q$["Use on one WordPress site","Unlimited courses and learners","Drip content, quizzes, certificates, and badges","1 year of updates and support","15-day money-back guarantee"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$10 Sites License$q$, $q$$399$q$, $q$per year$q$, $q$["Use across up to 10 WordPress sites","Unlimited courses and learners","Same feature set as the 1-site plan","1 year of updates and support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Unlimited Sites License$q$, $q$$799$q$, $q$per year$q$, $q$["Use across unlimited WordPress sites","Lowest per-site cost for agencies and developers","Unlimited courses and learners","1 year of updates and support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$LearnDash Cloud (Essential)$q$, $q$$348$q$, $q$per year$q$, $q$["Fully hosted, managed LearnDash environment","Unlimited courses and learners","Managed infrastructure and updates","No separate WordPress hosting required"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LearnDash is a learning management system (LMS) plugin built for WordPress, letting site owners turn an existing WordPress site into a full course platform. Rather than hosting content on a separate SaaS platform, LearnDash installs directly into WordPress, giving course creators complete ownership of their content, student data, and design while still tapping into the plugin's course-building, quizzing, and monetization tools.$q$, $q$Originally released in 2013, LearnDash grew into one of the most widely used WordPress LMS plugins, adopted by universities, corporate training teams, and independent course creators alike. It was acquired by Liquid Web in 2021 and operated for several years under the StellarWP umbrella brand alongside other WordPress products; in 2026 Liquid Web consolidated its WordPress software portfolio, folding the standalone StellarWP brand and continuing LearnDash as one of its core products.$q$, $q$At its core, LearnDash provides a drag-and-drop course builder, quiz engine, drip-feed content scheduling, certificates and badges, and integrations with payment processors like WooCommerce and Stripe for selling courses and memberships. Because it runs on WordPress, it also inherits the flexibility of the broader WordPress plugin and theme ecosystem, making it a popular choice for anyone who wants a self-hosted alternative to hosted course platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$who-learndash-is-for$q$, $q$Who LearnDash Is For$q$, 2, ARRAY[$q$LearnDash is best suited to people who already run, or are comfortable running, a WordPress site and want full control over their course business rather than being tied to a hosted platform's branding, fees, or feature limits. This includes coaches, consultants, and content creators who want to sell courses directly from their own domain and keep all customer relationships and payment data in-house.$q$, $q$It also fits organizations with more structured training needs: corporate L&D teams building internal certification programs, associations and membership sites that gate content behind subscriptions, and educational institutions running blended or fully online programs. LearnDash's group management, bulk enrollment, and reporting tools make it practical for managing cohorts of learners rather than just individual customers.$q$, $q$Developers and agencies that build and maintain WordPress sites for clients are another strong fit, since LearnDash's licensing scales by number of sites and its open architecture allows deep customization via hooks, add-ons, and theme integration. Anyone who values owning their content and audience over the convenience of an all-in-one hosted tool will generally find LearnDash a good match.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$LearnDash is not a great fit for people who want to launch a course quickly without touching WordPress. Because it is a plugin rather than a standalone hosted product, it requires a working WordPress installation, hosting, and at least basic familiarity with plugins, themes, and updates. Beginners who want a fully managed, all-in-one course platform may find the setup overhead frustrating.$q$, $q$Creators on a very tight budget should also be cautious. LearnDash itself has no free plan or free trial, and the base license price is often just the starting point once hosting, a compatible theme, and commonly needed add-ons (for design, marketing automation, or advanced quizzing) are factored in. Those costs can add up quickly compared with simpler hosted course tools with predictable flat pricing.$q$, $q$Finally, anyone uneasy with recent changes in LearnDash's corporate structure — including the 2026 wind-down of the standalone StellarWP brand and consolidation under Liquid Web — may want to watch how support and roadmap priorities evolve before committing a large course business to the platform. Teams that need guaranteed uptime SLAs and fully managed infrastructure without any server administration may prefer a hosted LMS instead.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$LearnDash's course builder lets creators structure content into courses, lessons, and topics, with support for drip-feeding lessons on a schedule, prerequisite completion rules, and dynamic content locking. Its quiz engine supports multiple question types, timed assessments, custom grading, and a Quiz AI Builder that can generate draft quiz questions from a course description using an integrated OpenAI connection.$q$, $q$Beyond course delivery, LearnDash includes certificates and badges for completed courses, course-specific discussion forums (via bbPress/BuddyPress integration), and gamification elements like points to encourage engagement. Group management tools allow administrators to bulk-enroll learners, assign group leaders, and track progress across teams, which is useful for corporate training and educational cohorts.$q$, $q$For monetization, LearnDash integrates with WooCommerce, Stripe, PayPal, and other payment tools to sell individual courses, bundles, or recurring memberships, and it connects with popular email marketing and CRM tools. ProPanel, LearnDash's reporting dashboard, gives site owners visibility into enrollment, completion rates, and learner engagement across all their courses.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$the-learndash-experience$q$, $q$The LearnDash Experience$q$, 2, ARRAY[$q$Setting up LearnDash means installing it like any other WordPress plugin, then working through its course builder interface to add lessons, topics, and quizzes. The learning curve is steeper than a purpose-built hosted LMS, since users are also managing WordPress itself, but the payoff is a course site that looks and feels like a natural extension of an existing brand rather than a bolted-on third-party portal.$q$, $q$Day-to-day, instructors spend most of their time in the course builder and quiz editor, while students interact with courses through a front-end learner dashboard that shows progress, certificates, and upcoming lessons. Because LearnDash is theme-agnostic, the actual look of the learner experience varies significantly depending on the WordPress theme and page builder used alongside it.$q$, $q$Overall, the experience rewards users who are willing to invest time in configuration and are comfortable troubleshooting WordPress plugin conflicts or hosting quirks. In exchange, they get a highly customizable, self-hosted course platform with no per-student fees, full data ownership, and access to the vast WordPress ecosystem of themes, page builders, and marketing tools.$q$]::text[], 4);
