INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Canvas Editor$q$, $q$Inpaint, outpaint, and edit specific regions of an image while keeping the rest of the composition intact.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Alchemy Rendering$q$, $q$An advanced rendering pipeline that improves lighting, detail, and overall image coherence.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$PhotoReal Mode$q$, $q$A dedicated mode tuned for highly realistic, photographic-style output.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Consistent Character$q$, $q$Keep a character's appearance stable across multiple generated scenes and poses.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$AI Upscaler$q$, $q$Increase resolution and sharpen detail on generated images for production use.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Motion and Video Tools$q$, $q$Turn still images into short animated clips or add subtle motion effects.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$API Access$q$, $q$Integrate Leonardo's generation and training capabilities directly into external apps and pipelines.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Community Model Sharing$q$, $q$Browse, use, and share fine-tuned models and prompts created by other users on the platform.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Wide range of models and styles suited to production work, not just artistic exploration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Strong tools for game assets, textures, and consistent character generation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Custom model training gives teams repeatable, on-brand results$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Free plan lets new users try core generation features before paying$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Canvas-based editing offers more precise control than simple prompt-only tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$The range of models and settings can feel overwhelming to first-time users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Token-based usage on lower tiers can run out quickly with heavy use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Some advanced features are gated behind higher-priced plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Licensing and commercial usage rights vary by plan and require careful review$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$No fully offline or self-hosted option for teams needing local control$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Is Leonardo AI free to use?$q$, $q$Yes, Leonardo AI offers a free plan with a limited daily token allowance for image generation, with paid plans available for higher usage and additional features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Who owns Leonardo AI?$q$, $q$Leonardo AI was founded in Sydney in 2022 and was acquired by design platform Canva in 2024, though it continues to operate as its own product.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Can I train my own custom model on Leonardo AI?$q$, $q$Yes, paid plans support training custom models on your own reference images or art style for consistent, repeatable output.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Does Leonardo AI have an API?$q$, $q$Yes, Leonardo AI provides API access so developers can integrate its image generation and training features into their own applications.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$What is Leonardo AI best used for?$q$, $q$It's widely used for game asset and concept art creation, marketing visuals, product mockups, and general AI art generation with fine-grained style control.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Game Asset and Concept Art Creation$q$, $q$Generate characters, environments, props, and textures using custom-trained models to match a game's specific art direction.$q$, $q$Game developers and concept artists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Marketing and Social Content$q$, $q$Produce on-brand visuals, ad creative, and social media graphics quickly without commissioning custom illustration for every asset.$q$, $q$Marketers and small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Product and Mockup Visualization$q$, $q$Create realistic product renders or scene mockups for e-commerce and presentations using PhotoReal generation.$q$, $q$E-commerce teams and product designers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Personal AI Art Projects$q$, $q$Explore art styles, train personal models, and generate illustrations or portraits with detailed creative control.$q$, $q$Independent artists and hobbyists$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["Daily token allowance for image generation","Access to core models","Community model browsing","Limited private generation options"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Apprentice$q$, $q$$12/month$q$, $q$Monthly$q$, $q$["Larger monthly token allowance","Private generations","Custom model training","Consistent Character tool access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Artisan$q$, $q$$30/month$q$, $q$Monthly$q$, $q$["Higher monthly token allowance","PhotoReal mode included","Alchemy rendering without extra per-use cost","Priority generation speed"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Maestro$q$, $q$$60/month$q$, $q$Monthly$q$, $q$["Highest monthly token allowance","Full access to advanced rendering and editing tools","Best suited for heavy production workloads","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Leonardo AI is a generative AI platform for producing images, textures, and visual assets from text prompts. Founded in Sydney in 2022, it built a following among game studios and digital artists before being acquired by design giant Canva in 2024, which now backs its continued development while Leonardo operates as a distinct product.$q$, $q$The platform is built around a library of pre-trained and community fine-tuned models, alongside its own proprietary Phoenix model, giving users control over art style, from photorealism to anime to game-ready textures. Its Alchemy rendering pipeline and PhotoReal mode push toward higher fidelity and more coherent lighting, composition, and detail than many general-purpose generators.$q$, $q$Where tools like Midjourney emphasize painterly, exploratory output through a chat interface, Leonardo leans into a full web-based studio: canvas editing, model training, upscaling, and motion tools live in one workspace, positioning it as a production tool for teams that need consistent, reusable visual assets rather than one-off art.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$who-leonardo-ai-is-for$q$, $q$Who Leonardo AI Is For$q$, 2, ARRAY[$q$Game developers and concept artists are core users, relying on Leonardo to generate characters, environments, and textures quickly, then fine-tune custom models on their own art style so output stays consistent across a project.$q$, $q$Marketers, social media managers, and small business owners use it to produce on-brand visuals, product mockups, and ad creative without hiring a designer for every asset, especially now that Canva's ecosystem is folding it into broader content workflows.$q$, $q$Independent creators, illustrators, and AI art hobbyists who want more granular control than a simple prompt box also gravitate here, since Leonardo exposes settings like guidance strength, ControlNet-style structure references, and model mixing that reward experimentation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who just want the fastest, simplest path from prompt to image may find Leonardo's model library, settings, and canvas tools more complex than they need compared to a stripped-down single-model generator.$q$, $q$Organizations with strict, pre-defined enterprise licensing or IP-indemnification requirements should carefully review Leonardo's terms for their specific plan before committing, since usage rights and commercial licensing can vary by tier.$q$, $q$People who specifically want to self-host open-weight models for full local control, offline use, or custom infrastructure won't get that from Leonardo, since it is a hosted cloud service rather than a downloadable, self-run model.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$A large model catalog spans photorealism, illustration, anime, and game-asset styles, and users can fine-tune their own custom models (including LoRA-style training) on a specific character, product, or art direction for repeatable, on-brand output.$q$, $q$The Canvas Editor supports inpainting, outpainting, and structure-guided generation, letting users edit part of an existing image, extend backgrounds, or lock in poses and layouts while regenerating everything else around them.$q$, $q$Alchemy and PhotoReal rendering modes improve lighting, detail, and coherence for higher-fidelity output, while built-in upscaling, a Consistent Character tool, and motion/video features extend static images into more production-ready formats.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$the-leonardo-ai-experience$q$, $q$The Leonardo AI Experience$q$, 2, ARRAY[$q$The web app organizes generation, training, and editing into distinct panels, so a session typically moves from picking or training a model, to prompting, to refining a chosen result in the canvas—more structured than a single chat-style prompt box.$q$, $q$A community feed of shared prompts, models, and finished images gives new users a fast way to learn effective prompting and discover fine-tuned models built by other creators, which softens the platform's initial learning curve.$q$, $q$Since joining Canva, Leonardo has continued operating as its own destination while gaining tighter integration paths into Canva's broader design ecosystem, making it a practical choice for teams that want AI image generation to feed directly into everyday design and marketing work.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
