INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Contact Management$q$, $q$Store detailed contact and company records with custom fields, notes, and file attachments tailored to your business.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Customizable Pipeline$q$, $q$Track deals and leads through configurable pipeline stages that match your own sales process rather than a fixed template.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Calendar and Task Management$q$, $q$Schedule appointments and follow-up tasks alongside contact records, with two-way syncing to Gmail and Outlook calendars.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Lead Tracking$q$, $q$Capture and organize incoming leads so nothing falls through the cracks as prospects move toward becoming customers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Custom Fields and Groups$q$, $q$Segment contacts and customize data fields to reflect the specific information that matters to your industry or workflow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Reporting$q$, $q$Generate simple reports on pipeline activity, lead sources, and team performance without needing a data analyst.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Mobile Apps$q$, $q$Access contacts, tasks, and the calendar on the go with native apps for iOS and Android devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Email Integration$q$, $q$Log and sync emails with Gmail or Outlook so conversation history stays attached to the right contact automatically.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$API and Zapier Integrations$q$, $q$Connect Less Annoying CRM to other business tools through its open API or pre-built Zapier automations.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Team Permissions$q$, $q$Set user-level access controls so teams can share a CRM instance while keeping sensitive records appropriately restricted.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Single flat price per user with no confusing tiers or hidden fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Easy to learn and set up, even for non-technical small business owners$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Highly responsive phone and email support included at no extra cost$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Customizable fields and pipelines adapt to many small business workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$30-day free trial with no credit card required to get started$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Lacks built-in marketing automation and email campaign tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Limited advanced analytics and forecasting compared to enterprise CRMs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Smaller integration ecosystem than larger CRM platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Minimal AI-driven features for lead scoring or sales insights$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$May feel too basic for larger sales teams with complex processes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$How much does Less Annoying CRM cost?$q$, $q$Less Annoying CRM uses a single flat price of $15 per user per month, with all features included and no separate pricing tiers.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Does Less Annoying CRM offer a free trial?$q$, $q$Yes, it offers a 30-day free trial with full access to the product, and no credit card is required to sign up.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Is there a free plan for Less Annoying CRM?$q$, $q$No, there is no permanent free plan, but the 30-day free trial provides complete access before any payment is required.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Does Less Annoying CRM integrate with email?$q$, $q$It integrates with Gmail and Outlook for two-way calendar syncing and email logging, and connects to other tools via Zapier and its API.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Is there a mobile app for Less Annoying CRM?$q$, $q$Yes, native mobile apps are available for both iOS and Android, allowing users to manage contacts and tasks away from their desktop.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Solo entrepreneur contact and lead organization$q$, $q$A single-person business uses the CRM to centralize contacts, notes, and follow-up reminders without a complex setup process.$q$, $q$Freelancers and solo entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Small sales team pipeline tracking$q$, $q$A small sales team customizes a pipeline to track deals from first contact through close, keeping everyone aligned on status.$q$, $q$Small business sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Insurance and real estate lead follow-up$q$, $q$Agents track leads and client renewals over time, using custom fields to record policy details or property preferences.$q$, $q$Insurance agents and real estate professionals$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Service business scheduling and task coordination$q$, $q$A small service business coordinates appointments, tasks, and client history in one shared calendar and contact system.$q$, $q$Small service-based businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Free Trial$q$, $q$Free$q$, $q$30 days$q$, $q$["Full access to all CRM features","No credit card required to start","Unlimited contacts during the trial","Cancel anytime with no obligation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Standard Plan$q$, $q$$15/user/month$q$, $q$Monthly$q$, $q$["Unlimited contacts and custom fields","Customizable pipeline and lead tracking","Mobile apps for iOS and Android","Phone and email support included","API and Zapier integrations"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Less Annoying CRM is a customer relationship management tool built specifically for small businesses that find traditional enterprise CRMs overwhelming. Founded in 2009 by brothers Tyler and Bracken King in St. Louis, Missouri, the company set out to build a CRM that avoided the bloat, steep learning curves, and confusing pricing tiers common in the category.$q$, $q$The product centers on the fundamentals of contact management: storing customer and lead information, tracking notes and communication history, managing a sales pipeline, and keeping a shared calendar and task list. Rather than chasing every trending CRM feature, Less Annoying CRM has stayed narrowly focused on making these core workflows fast and intuitive for non-technical users.$q$, $q$Its business model reflects the same philosophy as its product: a single flat price per user, with every feature included and no separate tiers to compare. Prospective customers can try the full product for 30 days without providing a credit card, which reinforces the company's positioning as a low-friction, low-risk alternative to larger CRM platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$who-its-for$q$, $q$Who Less Annoying CRM Is For$q$, 2, ARRAY[$q$Less Annoying CRM is best suited to solo entrepreneurs, freelancers, and very small teams who need a place to organize contacts and leads but have been frustrated by the complexity of platforms like Salesforce or HubSpot. Its straightforward setup and minimal configuration make it approachable for people without a dedicated sales operations or IT resource.$q$, $q$Service-based businesses tend to be a particularly strong fit, including insurance agents, financial advisors, consultants, and small real estate teams that primarily need to track relationships, follow-up tasks, and pipeline stages rather than run sophisticated multi-channel marketing campaigns. Its customizable pipelines and fields adapt reasonably well to these varied workflows.$q$, $q$It also appeals to small teams that place a high value on responsive, human customer support and predictable costs. Because pricing is per user with no hidden add-ons, growing teams can budget confidently, and the emphasis on plain-language help documentation and live support suits buyers who want quick answers without navigating a large support bureaucracy.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger organizations with complex sales operations, multiple departments, or elaborate approval workflows will likely outgrow Less Annoying CRM quickly. It was never designed to handle the layered permission structures, advanced forecasting, or cross-team reporting that bigger sales organizations typically require.$q$, $q$Businesses that rely heavily on marketing automation, such as multi-step email drip campaigns, landing page builders, or advanced lead scoring, should look elsewhere, since Less Annoying CRM does not build these capabilities natively into the product. Companies wanting integrated e-commerce or advanced AI-driven sales insights will also find the feature set comparatively limited.$q$, $q$Finally, teams that depend on a large ecosystem of pre-built integrations and marketplace apps, similar to what platforms like Salesforce or HubSpot offer, may find the available connections here more limited. While Zapier and a handful of native integrations cover common needs, businesses with highly specialized tech stacks may need more extensive integration support than the platform currently provides.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Less Annoying CRM offers centralized contact management with customizable fields, notes, and file attachments, letting users tailor records to whatever information matters most to their business. A visual, customizable pipeline helps teams track deals or leads through defined stages without forcing a rigid, one-size-fits-all sales process.$q$, $q$Built-in calendar and task management keep follow-ups and appointments visible alongside contact records, while lead tracking and simple reporting dashboards give small teams a clear view of pipeline activity and performance without requiring a business intelligence background to interpret them.$q$, $q$The platform also includes mobile apps for iOS and Android, two-way calendar syncing and email logging with Gmail and Outlook, and API access for teams that want to build custom connections. Native and Zapier-based integrations extend the CRM to other tools small businesses commonly rely on, such as email marketing services and web forms.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$the-experience$q$, $q$The Less Annoying CRM Experience$q$, 2, ARRAY[$q$New users typically describe the onboarding process as fast and low-friction, with a short setup wizard and minimal required configuration before the CRM is usable. There is little of the implementation overhead associated with larger enterprise CRM deployments, which is a deliberate design choice reflected throughout the product.$q$, $q$Day-to-day use is characterized by an uncluttered, text-forward interface that prioritizes speed over visual flourish. Users consistently point to the responsiveness of phone and email support, which is included at no extra cost, as a standout part of the experience compared to CRMs that gate direct support behind higher-priced tiers.$q$, $q$Overall sentiment toward Less Annoying CRM is shaped by a clear tradeoff: buyers who value simplicity, transparent pricing, and quick time-to-value tend to be very satisfied, while those hoping for deep customization, automation, or advanced analytics often find the experience intentionally, and sometimes noticeably, basic.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
