INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Applicant Tracking System$q$, $q$Manage requisitions, applications, and candidate pipelines with customizable stages tailored to each role or department.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Built-in CRM & Sourcing$q$, $q$Maintain talent pools of past applicants and passive candidates and re-engage them with targeted outreach instead of sourcing from scratch.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Structured Interviewing$q$, $q$Standardize evaluation with customizable interview kits and scorecards so feedback stays consistent across interviewers and roles.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Interview Scheduling$q$, $q$Coordinate interviewer availability and calendar invites directly from the candidate profile, reducing manual back-and-forth.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Nurture & Email Campaigns$q$, $q$Send segmented, automated email campaigns to keep candidate pools warm between hiring cycles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Reporting & Analytics$q$, $q$Track funnel metrics, time-to-hire, source effectiveness, and diversity data through configurable dashboards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Career Sites & Job Postings$q$, $q$Publish and syndicate job openings to a branded careers page and external job boards from one place.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Integrations & API$q$, $q$Connect Lever to HRIS, background check, assessment, video interview, and calendar tools via native integrations and an open API.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Workflow Automation$q$, $q$Automate repetitive recruiting tasks, such as stage transitions and follow-up reminders, to reduce manual coordination.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$AI-Assisted Sourcing$q$, $q$Use AI-assisted matching and sourcing tools within the platform to help surface relevant candidates faster.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Combines ATS and CRM functionality in a single system, reducing the need for separate sourcing tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Strong reporting and analytics for tracking funnel health and hiring diversity metrics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Highly configurable pipelines and interview workflows that adapt to different hiring processes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Broad integration ecosystem with HRIS, calendar, and assessment tools plus an open API$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Well suited to teams doing proactive, ongoing sourcing rather than one-off hiring$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Pricing is not published and requires a sales conversation, which can be a barrier for smaller teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Initial setup and configuration require meaningful time investment before the platform delivers full value$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Geared toward mid-market and enterprise use, so it can feel like overkill for very low-volume hiring$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Effectiveness depends on recruiters actively maintaining CRM data and candidate pools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Some users report a learning curve for admins configuring pipelines, permissions, and automations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Is Lever free to use?$q$, $q$No, Lever does not offer a free plan. It is sold as enterprise software with custom, quote-based pricing determined through a sales conversation.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$What is LeverTRM?$q$, $q$LeverTRM is Lever's branding for its combined applicant tracking system and candidate relationship management (CRM) platform, unifying hiring and sourcing in one product.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Who owns Lever?$q$, $q$Lever was acquired by Employ Inc. in 2022, joining Employ's portfolio alongside JazzHR and Jobvite, though Lever continues to operate under its own brand.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Does Lever integrate with other HR tools?$q$, $q$Yes, Lever offers native integrations with HRIS, background check, assessment, video interview, and calendar tools, along with an open API for custom connections.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$What size companies use Lever?$q$, $q$Lever primarily serves mid-market and enterprise organizations with dedicated recruiting teams, rather than very small businesses or occasional hirers.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Scaling a technology company's hiring$q$, $q$A growth-stage tech company uses Lever to manage high volumes of engineering and go-to-market requisitions with consistent, structured interview processes across teams.$q$, $q$Talent acquisition teams at scaling technology companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Proactive candidate sourcing and nurture$q$, $q$Recruiters build and segment talent pools of passive candidates, running nurture campaigns to keep them engaged until relevant roles open.$q$, $q$Sourcers and recruiters focused on outbound talent pipelines$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Standardizing interview quality$q$, $q$A hiring team rolls out structured interview kits and scorecards in Lever to reduce bias and inconsistency across hiring managers and panels.$q$, $q$Recruiting operations and hiring managers standardizing interview processes$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Hiring analytics and DEI reporting$q$, $q$Talent leadership uses Lever's reporting dashboards to monitor time-to-hire, source performance, and diversity metrics across the hiring funnel.$q$, $q$VPs of Talent and recruiting leadership tracking hiring metrics$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Core ATS$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Applicant tracking and pipeline management","Career site and job posting tools","Interview scheduling and scorecards","Standard reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$LeverTRM (ATS + CRM)$q$, $q$Custom pricing$q$, $q$Annual contract$q$, $q$["Everything in Core ATS","Built-in CRM and talent pool sourcing","Nurture and email campaign tools","Advanced reporting and analytics","Workflow automation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Annual contract$q$, $q$["Everything in LeverTRM","Advanced integrations and API access","Dedicated onboarding and customer success support","Custom permissions and enterprise-grade security controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lever is a talent acquisition platform, marketed as LeverTRM, that combines a traditional applicant tracking system (ATS) with a candidate relationship management (CRM) layer in a single product. Rather than treating sourcing, pipeline management, and hiring as separate tools, Lever lets recruiting teams manage the entire candidate journey, from first outreach to signed offer, inside one system of record.$q$, $q$Founded in 2012 in San Francisco, Lever grew into one of the more recognizable names in enterprise recruiting software before being acquired by Employ Inc. in 2022, joining sibling products JazzHR and Jobvite under the same parent company. Lever continues to operate as its own brand aimed primarily at mid-market and enterprise talent acquisition teams.$q$, $q$The platform is built around visual, customizable pipelines, structured interview feedback, and reporting that gives talent leaders visibility into funnel health, diversity metrics, and hiring velocity. It integrates with common HRIS, calendaring, background check, and assessment tools, positioning itself as the connective layer between sourcing activity and downstream people systems.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$who-lever-is-for$q$, $q$Who Lever Is For$q$, 2, ARRAY[$q$Lever is best suited to in-house talent acquisition teams at mid-market and enterprise companies that hire consistently throughout the year rather than in occasional bursts. Organizations with dedicated recruiters, sourcers, and recruiting operations or coordination roles tend to get the most value, since the platform rewards teams that actively build and nurture candidate pipelines rather than posting jobs reactively.$q$, $q$Companies that need to combine outbound sourcing with structured, high-volume applicant management are a natural fit, particularly technology, growth-stage, and scaling organizations that compete for talent and want a CRM to keep past applicants and passive candidates warm. Teams that care about interview process consistency, structured scorecards, and hiring analytics will appreciate Lever's configurability.$q$, $q$Lever also suits organizations with existing HR tech stacks, since much of its value comes from integrating with HRIS, background check, assessment, and calendar tools already in use. Companies that already run structured hiring committees, DEI reporting, or multi-stage approval workflows can generally map those processes onto Lever's pipeline model without major compromises.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small companies or teams making only a handful of hires a year are likely to find Lever more platform than they need. The pricing model is enterprise-oriented and sold through a sales process rather than self-serve sign-up, which makes it a poor match for solo founders, small agencies, or teams that just need a lightweight job board and application inbox.$q$, $q$Organizations without any dedicated recruiting headcount may also struggle, since Lever's CRM and sourcing features assume someone is actively managing pipelines, running nurture campaigns, and maintaining data hygiene. Hiring managers looking for a purely self-service, plug-and-play tool with minimal setup may find the initial configuration heavier than expected.$q$, $q$Budget-constrained teams that want transparent, published pricing may also be frustrated, since Lever pricing is quote-based and typically requires a sales conversation rather than a visible price list. Teams that primarily need staffing-agency features, payroll, or full HRIS functionality will need to pair Lever with other systems rather than expect it to cover those needs natively.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Lever offers a visual, drag-and-drop candidate pipeline alongside built-in CRM tools for sourcing and nurturing talent pools, so recruiters can track both active applicants and passive candidates in the same workspace. Career site and job posting tools let teams publish openings and syndicate them across job boards without leaving the platform.$q$, $q$Structured interviewing features, including customizable scorecards, interview kits, and scheduling tools, help standardize how interviewers evaluate candidates and reduce inconsistency across hiring teams. Automation and email/nurture campaign tools let recruiters re-engage past applicants or silver-medalist candidates instead of starting sourcing from zero for every requisition.$q$, $q$Reporting and analytics dashboards surface funnel metrics, time-to-hire, source effectiveness, and diversity data for talent leadership, while an open API and a marketplace of integrations connect Lever to HRIS, background check, assessment, video interviewing, and calendar tools. Lever has also introduced AI-assisted capabilities aimed at speeding up sourcing and candidate matching within the platform.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$the-lever-experience$q$, $q$The Lever Experience$q$, 2, ARRAY[$q$Day to day, Lever centers on a pipeline view where recruiters move candidates through customizable stages, log notes and feedback, and trigger next steps like scheduling or automated emails. The interface groups requisitions, candidates, and CRM contacts in a way that keeps sourcing and active hiring visible side by side rather than in separate tools.$q$, $q$New teams typically go through a guided implementation to configure pipeline stages, interview kits, permissions, and integrations to match their existing hiring process, which means the first few weeks involve real setup work rather than an instant out-of-the-box experience. Once configured, most day-to-day usage revolves around scheduling, feedback collection, and email/nurture activity.$q$, $q$Ongoing use tends to reward teams that keep their CRM data current and lean on Lever's reporting to inform hiring decisions, rather than treating it purely as an applicant inbox. Support and account management are geared toward its enterprise customer base, with dedicated onboarding and customer success involvement being part of the typical purchasing experience.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
