INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6395be6b-6a6a-42ae-a6f6-77c85ea825f2', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Issue tracking$q$, $q$Create, assign, and prioritize issues with a fast, keyboard-driven command menu built for high-velocity engineering teams.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Cycles$q$, $q$Sprint-like recurring cycles help teams plan, commit to, and review a fixed batch of work on a regular cadence.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Projects and initiatives$q$, $q$Group related issues into projects and roll multiple projects up into initiatives for tracking larger, cross-team efforts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Roadmaps$q$, $q$Visual, timeline-based roadmaps let teams and stakeholders see planned work and progress without a separate slide deck.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Linear Insights$q$, $q$Built-in analytics surface throughput, cycle time, and workload trends to help teams spot bottlenecks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Triage inbox$q$, $q$A dedicated queue for incoming bug reports and requests lets teams review and route work before it enters a cycle.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Git and PR integrations$q$, $q$Link issues to branches, commits, and pull requests across GitHub, GitLab, and similar providers, with automatic status updates.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$AI-assisted triage$q$, $q$AI features help summarize, deduplicate, and route incoming issues to reduce manual backlog grooming.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$API and integrations$q$, $q$A public API plus integrations with Slack, Figma, Zendesk, and other tools connect Linear to the rest of a team's stack.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Cross-platform apps$q$, $q$Native desktop apps for Mac and Windows, plus mobile apps for iOS and Android, keep the same fast experience across devices.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Exceptionally fast, keyboard-first interface that reduces friction for high-frequency issue tracking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Clean, opinionated workflows (issues, cycles, projects) that require little setup to get a team productive$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Strong native Git integration that links issues to branches, commits, and pull requests automatically$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Generous free plan for small teams, with straightforward per-user pricing above that$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Consistent experience across web, desktop, and mobile clients with near real-time sync$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Less configurable than tools like Jira, which can be limiting for large organizations with complex processes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Not designed for non-technical departments such as marketing, sales, or HR$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Advanced features such as private teams, guest access, and AI triage require paid plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$No self-hosted or on-premise deployment option for teams with strict data-residency requirements$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$The free plan's issue and team limits mean growing teams will need to upgrade fairly quickly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$What is Linear used for?$q$, $q$Linear is used by software teams to track issues, plan work in cycles, manage projects and roadmaps, and coordinate engineering work alongside product and design collaborators.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Is Linear free to use?$q$, $q$Yes, Linear offers a free plan with unlimited members, a limited number of teams, and a capped number of issues, covering core issue tracking, projects, and cycles.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$How is Linear different from Jira?$q$, $q$Linear emphasizes speed and opinionated, low-configuration workflows, whereas Jira offers deeper customization and administrative controls aimed at larger, more complex organizations.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Does Linear integrate with GitHub and GitLab?$q$, $q$Yes, Linear integrates with major Git providers so that branches, commits, and pull requests can automatically update linked issue status.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Is there a Linear mobile app?$q$, $q$Yes, Linear provides native iOS and Android apps in addition to its web app and native Mac and Windows desktop applications.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Sprint-based engineering planning$q$, $q$Engineering teams use cycles to plan a fixed scope of work, track progress during the cycle, and review completed work afterward.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Cross-functional product roadmapping$q$, $q$Product managers use projects and initiatives to plan multi-team features and share visual roadmaps with stakeholders.$q$, $q$Product managers and leadership$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Bug and request triage$q$, $q$Support and engineering teams route incoming bug reports and feature requests through the Triage inbox before they enter active work.$q$, $q$Support and engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Startup product development$q$, $q$Early-stage startups adopt Linear as a lightweight, all-in-one system for tracking their first product roadmap without heavy process overhead.$q$, $q$Startup founders and small product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Unlimited members","Up to 2 teams","Up to 250 issues","Core issue tracking, projects, and cycles"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Basic$q$, $q$$10/user/month$q$, $q$Annual (monthly available at a higher rate)$q$, $q$["Unlimited issues","Up to 5 teams","Core Linear workflows","Standard integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Business$q$, $q$$16/user/month$q$, $q$Annual (monthly available at a higher rate)$q$, $q$["Unlimited teams","Private teams and guest access","Linear Insights analytics","AI-assisted triage features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["SAML/SCIM and advanced security","Dedicated support","Advanced admin controls","Custom contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Linear is a project management and issue-tracking application built specifically for software teams, founded in 2019 and headquartered in San Francisco. It was designed as an alternative to heavier, more configurable tools like Jira, prioritizing speed, a minimal interface, and opinionated workflows over exhaustive customization.$q$, $q$The product centers on issues, cycles (Linear's take on sprints), and projects, all wrapped in a keyboard-first interface that lets engineers and product managers move through the app without touching a mouse. Linear syncs in near real time across web, desktop, and mobile clients, and integrates tightly with Git providers so that branches, commits, and pull requests can update issue status automatically.$q$, $q$Over time, Linear has expanded from a lightweight tracker into a fuller planning suite, adding roadmaps, initiatives for grouping related projects, an insights and analytics layer, and AI-assisted features such as issue triage and summarization. It has become a common choice among startups and product-led engineering organizations that want structure without the overhead of legacy enterprise tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$who-linear-is-for$q$, $q$Who Linear Is For$q$, 2, ARRAY[$q$Linear is aimed primarily at software engineering and product teams that ship frequently and want their tracker to keep pace with that cadence. Startups and scale-ups building a single core product tend to be the strongest fit, since Linear's structure of teams, cycles, and projects maps closely to how small, fast-moving engineering organizations already work.$q$, $q$Product managers and designers who collaborate closely with engineers also benefit, since Linear treats issues, specs, and roadmaps as shared artifacts rather than engineering-only tickets. Its integrations with design and communication tools, such as Figma and Slack, make it easier to keep non-engineering stakeholders in the loop without duplicating work in a separate system.$q$, $q$Remote and distributed teams are another natural audience, since Linear was built by a fully remote company and reflects that in its async-friendly workflows, notifications, and status updates. Teams that already value keyboard-driven, low-friction software tend to adapt to Linear quickly and rarely go back to slower, form-heavy trackers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-department workflows that need extensive custom fields, approval chains, or portfolio-level governance may find Linear more restrictive than tools like Jira or Azure DevOps, which are built around deep configurability. Linear's opinionated defaults are a strength for small teams but can feel limiting once an organization's process requirements grow highly specialized.$q$, $q$Non-technical teams outside of product and engineering, such as marketing, sales, or HR, are generally not the intended audience; Linear's data model and vocabulary of issues, cycles, and triage are built around software delivery and don't translate cleanly to other kinds of work management.$q$, $q$Organizations that require heavy on-premise deployment, extensive legacy-system integrations, or highly bespoke reporting may also be better served elsewhere, since Linear is a cloud-hosted product with a comparatively focused integration and customization surface area.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Linear organizes work into issues grouped by team, project, and cycle, with a fast command menu triggered by a keyboard shortcut that lets users create, assign, and update issues without leaving the keyboard. Cycles function like sprints, giving teams a recurring cadence for planning and reviewing completed work.$q$, $q$Projects and initiatives let teams track larger bodies of work and multi-team efforts over time, with visual roadmaps and status updates that stakeholders can follow without attending a dedicated meeting. Linear Insights adds lightweight analytics on throughput and cycle time, while the Triage inbox helps teams process incoming bug reports and requests before they enter a workflow.$q$, $q$Git and developer-tool integrations connect issues directly to branches, commits, and pull requests across GitHub, GitLab, and similar providers, and an API plus native mobile and desktop apps round out the product. More recently, Linear has added AI-assisted features, including automated issue triage and duplicate detection, aimed at reducing manual backlog grooming.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$the-linear-experience$q$, $q$The Linear Experience$q$, 2, ARRAY[$q$Day to day, using Linear feels noticeably faster than most competing tools: page transitions are near-instant, and nearly every action has a keyboard shortcut, which appeals strongly to engineers who dislike clicking through nested menus. The interface is deliberately minimal, with a design language that has become something of a reference point in the project-management-software space.$q$, $q$New users typically need a short adjustment period to learn Linear's vocabulary and shortcuts, but teams that adopt it often report that the tool gets out of the way rather than becoming a chore to maintain. Its opinionated defaults mean less setup time compared to fully configurable trackers, at the cost of some flexibility for unusual workflows.$q$, $q$Overall, the experience is best summarized as fast by default: status updates, notifications, and sync across devices happen with little lag, and the emphasis on speed and clarity carries through consistently from the first issue created to long-running roadmap tracking across many cycles.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
