INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
